import { GoogleGenAI, Type } from "@google/genai";
import { TeachingMethod, LearningStyle } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateLessonPlan = async (params: {
  topic: string;
  grade: string;
  method: TeachingMethod;
  style: LearningStyle;
  needsComplexity: number; // 0-100 for complexity or adjustment level
}) => {
  const prompt = `
    أنت خبير تربوي ومصمم خطط دروس عبقري لموقع "معلم بلس".
    قم بإنشاء خطة درس مفصلة باللغة العربية حول الموضوع: ${params.topic}.
    الفئة المستهدفة: ${params.grade}.
    أسلوب التعليم المستخدم: ${params.method}.
    نمط التعلم التركيزي: ${params.style}.
    مستوى التخصيص للاحتياجات (0-100): ${params.needsComplexity}.

    يجب أن تتضمن الخطة:
    1. أهداف تعليمية ذكية.
    2. أنشطة صفية تفاعلية.
    3. أنشطة غير منهجية (مسلية وغامرة).
    4. وسائط تعليمية (بصرية، سمعية، حركية حسب النمط).
    5. دليل للمعلم (بصيرة تربوية) للتعمق في الموضوع وتوقع الأسئلة الصعبة.
    6. آلية تقييم.

    اجعل الأسلوب ملهماً وحديثاً جداً.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          objectives: { type: Type.ARRAY, items: { type: Type.STRING } },
          activities: { type: Type.ARRAY, items: { type: Type.STRING } },
          funActivities: { type: Type.ARRAY, items: { type: Type.STRING } },
          materials: { type: Type.ARRAY, items: { type: Type.STRING } },
          assessment: { type: Type.STRING },
          teacherInsight: { type: Type.STRING },
        },
        required: ["title", "objectives", "activities", "funActivities", "teacherInsight"]
      }
    }
  });

  return JSON.parse(response.text);
};

export const getTeacherGuideContent = async (topic: string) => {
  const prompt = `
    قدم دليلاً معرفياً عميقاً للمعلم حول موضوع "${topic}". 
    ركز على الحقائق العلمية المثبتة، تاريخ الموضوع، والأسئلة غير المتوقعة التي قد يطرحها الطلاب الأذكياء أو ذوي الاحتياجات الخاصة وكيفية الإجابة عليها ببساطة وعمق.
    استخدم مصادر تربوية موثوقة.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt
  });

  return response.text;
};

import React, { createContext, useContext, useState, useEffect } from 'react';
import { Theme } from '../types';

interface ThemeContextType {
  theme: Theme;
  toggleTheme: () => void;
}

const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

export const ThemeProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [theme, setTheme] = useState<Theme>('day');

  const toggleTheme = () => {
    setTheme(prev => (prev === 'day' ? 'night' : 'day'));
  };

  useEffect(() => {
    document.body.className = theme === 'day' ? 'bg-[#F5F5DC] text-slate-800' : 'bg-[#121212] text-gray-100';
  }, [theme]);

  return (
    <ThemeContext.Provider value={{ theme, toggleTheme }}>
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (!context) throw new Error('useTheme must be used within a ThemeProvider');
  return context;
};

