import { generateLessonPlan } from '../services/geminiService';

const LessonPlannerForm: React.FC<{ onResult: (res: any) => void }> = ({ onResult }) => {
  const { theme } = useTheme();
  const colors = THEME_COLORS[theme];
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({
    topic: '',
    grade: 'الصف الخامس',
    method: TeachingMethod.STEAM,
    style: LearningStyle.VISUAL,
    needsComplexity: 20
  });

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      const result = await generateLessonPlan(formData);
      onResult(result);
    } catch (error) {
      console.error(error);
      alert('حدث خطأ في توليد الخطة. يرجى المحاولة مرة أخرى.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className={`${colors.card} p-8 rounded-3xl shadow-xl border ${colors.border}`}>
      <h2 className="text-3xl font-bold mb-6 text-center">خطط لدرسك بذكاء</h2>
      <form onSubmit={handleSubmit} className="space-y-6">
        <div>
          <label className="block text-sm font-bold mb-2">موضوع الدرس</label>
          <input
            type="text"
            required
            className={`w-full p-4 rounded-xl border ${colors.border} ${theme === 'night' ? 'bg-gray-800' : 'bg-gray-50'}`}
            placeholder="مثال: دورة حياة النبات، التمثيل الضوئي..."
            value={formData.topic}
            onChange={(e) => setFormData({ ...formData, topic: e.target.value })}
          />
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div>
            <label className="block text-sm font-bold mb-2">المرحلة الدراسية</label>
            <select
              className={`w-full p-4 rounded-xl border ${colors.border} ${theme === 'night' ? 'bg-gray-800' : 'bg-gray-50'}`}
              value={formData.grade}
              onChange={(e) => setFormData({ ...formData, grade: e.target.value })}
            >
              <option>رياض الأطفال</option>
              <option>الصف الأول - الثالث</option>
              <option>الصف الرابع - السادس</option>
              <option>المرحلة الإعدادية</option>
              <option>المرحلة الثانوية</option>
            </select>
          </div>

          <div>
            <label className="block text-sm font-bold mb-2">أسلوب التعليم الحديث</label>
            <select
              className={`w-full p-4 rounded-xl border ${colors.border} ${theme === 'night' ? 'bg-gray-800' : 'bg-gray-50'}`}
              value={formData.method}
              onChange={(e) => setFormData({ ...formData, method: e.target.value as TeachingMethod })}
            >
              {Object.values(TeachingMethod).map(m => (
                <option key={m} value={m}>{m}</option>
              ))}
            </select>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div>
            <label className="block text-sm font-bold mb-2">نمط الاستيعاب المفضل</label>
            <select
              className={`w-full p-4 rounded-xl border ${colors.border} ${theme === 'night' ? 'bg-gray-800' : 'bg-gray-50'}`}
              value={formData.style}
              onChange={(e) => setFormData({ ...formData, style: e.target.value as LearningStyle })}
            >
              {Object.values(LearningStyle).map(s => (
                <option key={s} value={s}>{s}</option>
              ))}
            </select>
          </div>

          <div>
            <label className="block text-sm font-bold mb-2">
              تخصيص الاحتياجات (مستوى الدعم) {formData.needsComplexity}%
            </label>
            <input
              type="range"
              className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-blue-600"
              value={formData.needsComplexity}
              onChange={(e) => setFormData({ ...formData, needsComplexity: parseInt(e.target.value) })}
