import { GoogleGenAI, Type } from "@google/genai";
import { TeachingMethod, LearningStyle } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateLessonPlan = async (params: {
  topic: string;
  grade: string;
  method: TeachingMethod;
  style: LearningStyle;
  needsComplexity: number;
}) => {
  const prompt = `
    أنت خبير تربوي ومصمم خطط دروس عبقري لموقع "معلم بلس".
    قم بإنشاء خطة درس مفصلة باللغة العربية حول الموضوع: ${params.topic}.
    الفئة المستهدفة: ${params.grade}.
    أسلوب التعليم المستخدم: ${params.method}.
    نمط التعلم التركيزي: ${params.style}.

    يجب أن تتضمن الخطة الأجزاء التالية بدقة:
    1. أهداف تعليمية ذكية.
    2. أنشطة صفية تفاعلية.
    3. أنشطة غير منهجية مسلية.
    4. دليل "الفهم العميق" للمعلم: 
       - معلومات علمية متقدمة حول الموضوع (Background).
       - 3 أسئلة صعبة وغير متوقعة قد يطرحها الطلاب الأذكياء أو الفضوليين مع إجابات نموذجية عميقة ومبسطة في آن واحد (QA).

    اجعل الأسلوب ملهماً وحديثاً جداً.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          objectives: { type: Type.ARRAY, items: { type: Type.STRING } },
          activities: { type: Type.ARRAY, items: { type: Type.STRING } },
          funActivities: { type: Type.ARRAY, items: { type: Type.STRING } },
          deepKnowledge: {
            type: Type.OBJECT,
            properties: {
              background: { type: Type.STRING },
              qa: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    q: { type: Type.STRING },
                    a: { type: Type.STRING }
                  },
                  required: ["q", "a"]
                }
              }
            },
            required: ["background", "qa"]
          }
        },
        required: ["title", "objectives", "activities", "deepKnowledge"]
      }
    }
  });

  return JSON.parse(response.text);
};

