import { GoogleGenAI, Type } from "@google/genai";
import { TeachingMethod, LearningStyle } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateLessonPlan = async (params: {
  topic: string;
  grade: string;
  method: TeachingMethod;
  style: LearningStyle;
  studentGroup: string;
}) => {
  const prompt = `
    أنت خبير تربوي عالمي ومصمم خطط دروس عبقري لموقع "معلم بلس".
    قم بإنشاء خطة درس استثنائية باللغة العربية حول الموضوع: ${params.topic}.
    المرحلة: ${params.grade}.
    المنهجية: ${params.method}.
    النمط: ${params.style}.
    فئة الطلاب: ${params.studentGroup}.

    المتطلبات الأساسية:
    1. اجعل المحتوى غنياً بالتفاصيل ولكن مختصراً ومباشراً (Bullet points).
    2. صمم الخطة بحيث تكون قابلة للتطبيق العملي الفوري.
    3. الأنشطة غير المنهجية يجب أن تكون "مسلية" وتخدم الهدف العلمي.
    4. دليل الفهم العميق يجب أن يغطي:
       - خلفية تاريخية أو فلسفية للمفهوم.
       - 3 أسئلة "ذكية" قد يطرحها الطالب الفضولي مع إجابات مبهرة.
       - نصائح للتعامل مع صعوبات الفهم الخاصة بهذا الموضوع تحديداً.

    صيغة الإخراج المطلوبة: JSON فقط.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          objectives: { type: Type.ARRAY, items: { type: Type.STRING } },
          activities: { type: Type.ARRAY, items: { type: Type.STRING } },
          funActivities: { type: Type.ARRAY, items: { type: Type.STRING } },
          deepKnowledge: {
            type: Type.OBJECT,
            properties: {
              background: { type: Type.STRING },
              qa: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    q: { type: Type.STRING },
                    a: { type: Type.STRING }
                  },
                  required: ["q", "a"]
                }
              }
            },
            required: ["background", "qa"]
          }
        },
        required: ["title", "objectives", "activities", "deepKnowledge"]
      }
    }
  });

  return JSON.parse(response.text);
};

