import React, { createContext, useContext, useState, useEffect } from 'react';
import { Theme } from '../types';

interface ThemeContextType {
  theme: Theme;
  toggleTheme: () => void;
}

const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

export const ThemeProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [theme, setTheme] = useState<Theme>('day');

  const toggleTheme = () => {
    setTheme(prev => (prev === 'day' ? 'night' : 'day'));
  };

  useEffect(() => {
    // We use standard white for day to match user request for white background
    document.body.className = theme === 'day' ? 'bg-white text-slate-900' : 'bg-[#121212] text-gray-100';
  }, [theme]);

  return (
    <ThemeContext.Provider value={{ theme, toggleTheme }}>
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (!context) throw new Error('useTheme must be used within a ThemeProvider');
  return context;
};

import React, { createContext, useContext, useState } from 'react';

interface AuthContextType {
  isLoggedIn: boolean;
  login: (email: string) => void;
  logout: () => void;
  user: { email: string; name: string } | null;
  savedPlans: any[];
  savePlan: (plan: any) => void;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [user, setUser] = useState<{ email: string; name: string } | null>(null);
  const [savedPlans, setSavedPlans] = useState<any[]>([]);

  const login = (email: string) => {
    setIsLoggedIn(true);
    setUser({ email, name: 'عبد الرحمن نجاجرة' }); // Mock name as per UI
  };

  const logout = () => {
    setIsLoggedIn(false);
    setUser(null);
    setSavedPlans([]);
  };

  const savePlan = (plan: any) => {
    // Avoid duplicates based on title for this mock
    if (!savedPlans.find(p => p.title === plan.title)) {
      setSavedPlans(prev => [plan, ...prev]);
    }
  };

  return (
    <AuthContext.Provider value={{ isLoggedIn, login, logout, user, savedPlans, savePlan }}>
      {children}
    </AuthContext.Provider>
  );
};

